CREATE CACHED TABLE IF NOT EXISTS "CLIENT_MAP_NODE" (
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "URL" VARCHAR(8192) NOT NULL,
    "NAME" VARCHAR(4096) NOT NULL,
    "VISITED" BOOLEAN NOT NULL,
    "STORAGE" BOOLEAN NOT NULL,
    "CONTENTLOADED" BOOLEAN NOT NULL,
    "REDIRECT" BOOLEAN NOT NULL,
);

CREATE CACHED TABLE IF NOT EXISTS "CLIENT_MAP_COMPONENT" (
    "CREATETIMESTAMP" TIMESTAMP NULL,
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    "NODE_ID" BIGINT NOT NULL,
    "TAGNAME" VARCHAR(1024) NULL,
    "ELEMENTID" VARCHAR(1024) NULL,
    "HREF" VARCHAR(8192) NULL,
    "TEXT" VARCHAR(8192) NULL,
    "TYPE" VARCHAR(256) NOT NULL,
    "TAGTYPE" VARCHAR(256) NULL,
    "FORMID" INTEGER NULL,

    CONSTRAINT "FK_CLIENT_MAP_COMPONENT_NODE" FOREIGN KEY ("NODE_ID") REFERENCES "CLIENT_MAP_NODE" ("ID") ON DELETE CASCADE,
);
